// FindHabit retrieves a single record by ID with an executor.
// If selectCols is empty Find will return all columns.
func FindHabit(ctx context.Context, exec boil.ContextExecutor, iD int16, selectCols ...string) (*Habit, error) {
	habitObj := &Habit{}

	sel := "*"
	if len(selectCols) > 0 {
		sel = strings.Join(strmangle.IdentQuoteSlice(dialect.LQ, dialect.RQ, selectCols), ",")
	}
	query := fmt.Sprintf(
		"select %s from \"habits\" where \"id\"=$1", sel,
	)

	q := queries.Raw(query, iD)

	err := q.Bind(ctx, exec, habitObj)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, sql.ErrNoRows
		}
		return nil, errors.Wrap(err, "entity: unable to select from habits")
	}

	if err = habitObj.doAfterSelectHooks(ctx, exec); err != nil {
		return habitObj, err
	}

	return habitObj, nil
}

